import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Notes from "./Notes";

export default function Dashboard() {
  const navigate = useNavigate();

  useEffect(() => {
    const isAuth = localStorage.getItem("isAuthenticated");

    if (!isAuth) {
      navigate("/");
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("isAuthenticated");
    navigate("/");
  };

  return (
    <div style={{ textAlign: "center", marginTop: "100px" }}>
      <h1>Welcome To My Personal Productivity Dashboard</h1>

      <button
        onClick={() => navigate("/tasks")}
        style={{
          marginTop: "20px",
          padding: "10px 20px",
          backgroundColor: "#306eab",
          color: "white",
          border: "none",
          cursor: "pointer",
          marginRight: "10px",
        }}
      >
        Go to Tasks
      </button>
      <button
        onClick={handleLogout}
        style={{
          marginTop: "20px",
          padding: "10px 20px",
          backgroundColor: "red",
          color: "white",
          border: "none",
          cursor: "pointer",
        }}
      >
        <button
  onClick={() => navigate("/notes")}
  style={{
    marginTop: "20px",
    padding: "10px 20px",
    backgroundColor: "#306eab",
    color: "white",
    border: "none",
    cursor: "pointer",
    marginLeft: "10px",
  }}
>
  Go to Notes
</button>
        Logout
      </button>
    </div>
  );
}
